import{_ as a,c as r,o,ag as t}from"./chunks/framework.piE7uVCg.js";const i="/assets/configuration.EduV1woA.png",n="/assets/colors.Daywu1Zh.png",f=JSON.parse('{"title":"HIKVISION","description":"","frontmatter":{},"headers":[],"relativePath":"securite/video/hikvision.md","filePath":"securite/video/hikvision.md"}'),s={name:"securite/video/hikvision.md"};function l(c,e,d,u,m,p){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="hikvision" tabindex="-1"><a href="./readme.html">HIKVISION</a> <a class="header-anchor" href="#hikvision" aria-label="Permalink to &quot;[HIKVISION](readme.md)&quot;">​</a></h1><h2 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h2><h2 id="rtsp-protocol" tabindex="-1">RTSP Protocol <a class="header-anchor" href="#rtsp-protocol" aria-label="Permalink to &quot;RTSP Protocol&quot;">​</a></h2><p>RTSP ou Real Time Streaming Protocol (protocole de streaming temps-réel) est un protocole de communication de niveau applicatif (niveau 7 du modèle OSI) destiné aux systèmes de streaming média. Il permet de contrôler un serveur de média à distance, offrant des fonctionnalités typiques d&#39;un lecteur vidéo telles que « lecture » et « pause », et permettant un accès en fonction de la position temporelle.</p><h3 id="formats" tabindex="-1">Formats <a class="header-anchor" href="#formats" aria-label="Permalink to &quot;Formats&quot;">​</a></h3><blockquote><p>rtsp://192.168.1.64/Streaming/channels/101 rtsp://username:password@192.168.1.64/Streaming/channels/101 <a href="https://www.hikvision.com/content/dam/hikvision/fr/guides-pratiques/autre/rtsp-and-http-urls-fr.pdf" target="_blank" rel="noreferrer">liens</a></p></blockquote><h2 id="logiciels-de-visualisation" tabindex="-1">Logiciels de visualisation <a class="header-anchor" href="#logiciels-de-visualisation" aria-label="Permalink to &quot;Logiciels de visualisation&quot;">​</a></h2><ul><li>VLC</li><li><a href="https://github.com/grigory-lobkov/rtsp-camera-view" target="_blank" rel="noreferrer">RTSP camera view</a> avec <a href="https://download.videolan.org/pub/videolan/vlc/2.1.5/win32/" target="_blank" rel="noreferrer">VLC 2.1.5</a></li><li><a href="https://github.com/grigory-lobkov/rtsp-camera-view/releases" target="_blank" rel="noreferrer">RTSP camera view</a></li><li><a href="https://play.google.com/store/apps/details?id=com.devinterestdev.streamshow" target="_blank" rel="noreferrer">StreamShow application mobile</a></li></ul><h2 id="video-tandem-ou-fisheye" tabindex="-1">Vidéo tandem ou fisheye <a class="header-anchor" href="#video-tandem-ou-fisheye" aria-label="Permalink to &quot;Vidéo tandem ou fisheye&quot;">​</a></h2><p>Pour configurer une caméra qui a plusieurs vues il faut configurer la caméras sur plusieurs ports avec la même adresse en changeant le numéro de port.</p><p><img src="'+i+'" alt="img"></p><h2 id="reparer-un-connecteur-endommage" tabindex="-1">Réparer un connecteur endommagé <a class="header-anchor" href="#reparer-un-connecteur-endommage" aria-label="Permalink to &quot;Réparer un connecteur endommagé&quot;">​</a></h2><p><img src="'+n+'" alt="code"></p>',13)])])}const g=a(s,[["render",l]]);export{f as __pageData,g as default};
